import{_ as e,o as i,c as t,a1 as a}from"./chunks/framework.CSfPkKfr.js";const o="/vp_step1.png",l="/vp_step2.png",r="/vp_step3.png",m=JSON.parse('{"title":"📝 小白实操：如何给自己的独立博客（VitePress）发布新文章？","description":"","frontmatter":{"title":"📝 小白实操：如何给自己的独立博客（VitePress）发布新文章？","date":"2026-03-31T00:00:00.000Z"},"headers":[],"relativePath":"tools/vitepress-publish.md","filePath":"tools/vitepress-publish.md"}'),p={name:"tools/vitepress-publish.md"};function n(d,s,c,h,g,k){return i(),t("div",null,[...s[0]||(s[0]=[a('<h1 id="📝-小白实操-如何给自己的独立博客-vitepress-发布新文章" tabindex="-1">📝 小白实操：如何给自己的独立博客（VitePress）发布新文章？ <a class="header-anchor" href="#📝-小白实操-如何给自己的独立博客-vitepress-发布新文章" aria-label="Permalink to &quot;📝 小白实操：如何给自己的独立博客（VitePress）发布新文章？&quot;">​</a></h1><p>当你成功搭建了像我一样极简清爽的独立博客（基于 VitePress + GitHub + Cloudflare Pages），肯定会面临一个问题：“我自己平时怎么发新文章呢？”</p><p>不用懂代码，不用懂运维。你只需要像写日记一样准备 <code>.md</code> 文件，然后靠 <strong>3 句魔法命令</strong>，你的网站就会全自动更新上线！</p><p>下面就是极简的发帖教程，小白一学就会！</p><hr><h2 id="📌-核心思路-你需要动哪几个文件夹" tabindex="-1">📌 核心思路：你需要动哪几个文件夹？ <a class="header-anchor" href="#📌-核心思路-你需要动哪几个文件夹" aria-label="Permalink to &quot;📌 核心思路：你需要动哪几个文件夹？&quot;">​</a></h2><p>在动手之前，我们先搞懂博客源码的结构。每次发帖，你只需要和下面这 <strong>3 个文件夹（或文件）</strong> 打交道：</p><p><img src="'+o+'" alt="第一步：理清三个核心位置"></p><h3 id="_1-准备你的文章-放在分类文件夹里" tabindex="-1">1. 准备你的文章（放在分类文件夹里） <a class="header-anchor" href="#_1-准备你的文章-放在分类文件夹里" aria-label="Permalink to &quot;1. 准备你的文章（放在分类文件夹里）&quot;">​</a></h3><ul><li><strong>文章格式</strong>：用任何编辑器（记事本、VS Code、Typora 等）写文章，保存为 <code>.md</code> 格式。例如：<code>my-new-post.md</code>。</li><li><strong>保存位置</strong>：把你写好的文章放到 <code>docs/</code> 下的某个分类文件夹里，比如 <code>docs/tools/</code>。</li></ul><h3 id="_2-把配图放进-public-文件夹" tabindex="-1">2. 把配图放进 <code>public</code> 文件夹 <a class="header-anchor" href="#_2-把配图放进-public-文件夹" aria-label="Permalink to &quot;2. 把配图放进 `public` 文件夹&quot;">​</a></h3><ul><li><strong>放图片</strong>：如果你的文章里带有截图，把所有的图片（如 <code>pic1.png</code>）一股脑扔进 <code>docs/public/</code> 文件夹里。</li><li><strong>引用图片</strong>：在文章里插入图片时，写这行代码：<code>![图注文字](/pic1.png)</code>。（记住斜杠 <code>/</code> 开头）。</li></ul><hr><h2 id="📌-核心操作-修改配置文件-让菜单显示你的文章" tabindex="-1">📌 核心操作：修改配置文件，让菜单显示你的文章 <a class="header-anchor" href="#📌-核心操作-修改配置文件-让菜单显示你的文章" aria-label="Permalink to &quot;📌 核心操作：修改配置文件，让菜单显示你的文章&quot;">​</a></h2><p>这一步很关键！文章放进去后，如果不在配置文件里“打个招呼”，网站左侧的菜单是不会显示它的。</p><ol><li>打开 <code>docs/.vitepress/config.js</code>（或 <code>config.mts</code>）。</li><li>往下翻，找到 <code>sidebar</code>（侧边栏）配置的地方。</li><li>照着下面这张图里的方法，在 <code>items</code> 中加入一行新文章的链接：</li></ol><p><img src="'+l+'" alt="第二步：让左侧菜单显示你的新文章"></p><blockquote><p><strong>⚠️ 注意事项</strong>：</p><ul><li><code>text</code> 是网站侧边栏显示的文字标题。</li><li><code>link</code> 是你文章的存放路径，前面加 <code>/</code>，后面<strong>不需要写 <code>.md</code> 后缀</strong>！</li></ul></blockquote><hr><h2 id="📌-魔法命令-一键推送到云端全自动发布" tabindex="-1">📌 魔法命令：一键推送到云端全自动发布 <a class="header-anchor" href="#📌-魔法命令-一键推送到云端全自动发布" aria-label="Permalink to &quot;📌 魔法命令：一键推送到云端全自动发布&quot;">​</a></h2><p>当你把文章写好了、图片放好了、配置文件也改好了，接下来就是见证奇迹的时刻！</p><p>打开你的终端（比如 SSH 连上你的虚拟机），进入博客根目录（<code>cd ~/vitepress-demo</code>），依次敲击下面这 <strong>3 行 Git 魔法命令</strong>：</p><p><img src="'+r+`" alt="第三步：命令行三连，一键全自动发布"></p><p>命令总结（直接复制粘贴执行即可）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;发布了一篇新文章&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><p><strong>✅ 大功告成！</strong> 只要这三行命令执行成功没有报错，一切就交给 Cloudflare 去全自动处理了。去泡杯咖啡，大约 1 到 2 分钟后，刷新你的网站网址，你的最新大作就已经成功上线啦！是不是超简单？</p>`,26)])])}const _=e(p,[["render",n]]);export{m as __pageData,_ as default};
